import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.IvParameterSpec;
import org.bouncycastle.util.io.pem.PemReader;

public class AESEncryptionUtil {
    private final static String KEY_ALGORITHM = "AES";
    private final static String TRANSFORMATION = KEY_ALGORITHM + "/CBC/PKCS5Padding";

    // Loads the key from a PEM-encoded file
    public static SecretKey loadSecretKey(String pemEncodedKeyFile) throws Exception {
        PemReader reader = new PemReader(getClass().getResourceAsStream(pemEncodedKeyFile));
        return reader.readObject();
    }

    // Encrypts the provided data using the given key and IV
    public static byte[] encryptData(SecretKey secretKey, IvParameterSpec iv, byte[] data) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, iv);
        return cipher.doFinal(data);
    }

    // Decrypts the provided encrypted data using the given key and IV
    public static byte[] decryptData(SecretKey secretKey, IvParameterSpec iv, byte[] encryptedData) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.DECRYPT_MODE, secretKey, iv);
        return cipher.doFinal(encryptedData);
    }
}